components.shader:
precision mediump float;
uniform sampler2D tSource;
uniform float uTime;
varying vec2 vUv;
void main() {
  vec2 center = vec2(0.5);
  vec2 p = vUv - center;
  // Mode 3: terra landing - slow zoom with slight rotation
  float scale1 = 0.90 + 0.05*sin(uTime*0.12);
  float turn1 = 0.015 + 0.008*sin(uTime*0.18);
  float cs = cos(turn1);
  float sn = sin(turn1);
  vec2 rotated = vec2(p.x*cs - p.y*sn, p.x*sn + p.y*cs);
  vec2 uv = rotated * (1.0/scale1) + center;
  // Horizontal wrapping
  uv.x = fract(uv.x);
  uv.y = clamp(uv.y, 0.0, 1.0);
  gl_FragColor = texture2D(tSource, uv) * 0.992;
}
